@use Phoenix.LiveView.Components, as: Component

defmodule PostLive do
  use PostLiveBehaviour

  # @impl LiveViewComponent
  def render(assigns) do
    ~L"""
    <div class="post">
      <h1><%= @post.title %></h1>

      <p><%= raw @post.content %></p>

      <%= Component.render("components/post_button", assigns: %{}) %>

    </div>
    """
  end

  def change(params, form_data) do
    {:ok, params}
  end
end

